import React, { useState } from 'react';
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import Login from './subfolder/Login';
import Nav from "./subfolder/Nav";
import ContactUs from "./subfolder/Contactus";
import Signup from './subfolder/Signup';
import AboutUs from './subfolder/About';
import HomeP from './subfolder/HomeP'; 
import Footer from './subfolder/Footer';
// import Gallery2 from './subfolder/pawanagallery';
// import WhatsBot from './subfolder/WhatsBot';
import Packages from './subfolder/package'; // Import Packages component
// import StayDetails from './subfolder/StayDetails'; // Import StayDetails component

function App() {
  const [selectedStay, setSelectedStay] = useState(null);

  // Function to handle when a package is clicked
  const handlePackageClick = (stayType) => {
    setSelectedStay(stayType);
  };

  // Function to go back to the packages list
  const handleBackClick = () => {
    setSelectedStay(null);
  };

  return (
    <Router>
      <Nav />
      <Routes>
        <Route path="/" element={<HomeP />} /> {/* Default route opens HomeP */}
        <Route path="/contact" element={<ContactUs />} />
        <Route path="/login" element={<Login />} /> {/* Route for Login */}
        <Route path="/aboutus" element={<AboutUs />} />
        <Route path="/create-account" element={<Signup />} />
        <Route path="/gallery" element={<Gallery2 />} /> {/* Route for Gallery2 */}
         {/* Route for WhatsBot */}
        <Route 
          path="/packages" 
          element={  
            selectedStay ? (
              <StayDetails stayType={selectedStay} onBack={handleBackClick} />
            ) : (
              <Packages onPackageClick={handlePackageClick} />
            )
          } 
        /> {/* Route for Packages and StayDetails */}
      </Routes>
      <Footer />
    </Router>
  );
}

export default App;
